import { ValidationPipe } from '@nestjs/common';
import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';

async function bootstrap() {
  const app = await NestFactory.create(AppModule);

  app.useGlobalPipes(new ValidationPipe({
    transform: true,              // string → number/boolean по типам DTO
    whitelist: true,              // удаляет поля, которых нет в DTO
    forbidNonWhitelisted: true,   // бросает 400, если переданы лишние поля
    stopAtFirstError: false,      // собрать все ошибки (или true — первая ошибка)
    transformOptions: { enableImplicitConversion: true }, // простые авто-конверсии
  }));

  await app.listen(3000);
}
bootstrap();
